// Scopes: stratum (demographic), district (region), global.

var ELECTORATE_PARTY_KEYS = ['D', 'I', 'C', 'G', 'H']

function electorateZeroScores() {
    return { D: 0, I: 0, C: 0, G: 0, H: 0 }
}

function electorateCopyScores(src) {
    var out = electorateZeroScores()
    for (var i = 0; i < ELECTORATE_PARTY_KEYS.length; i++) {
        var k = ELECTORATE_PARTY_KEYS[i]
        out[k] = (src && src[k]) || 0
    }
    return out
}

function electorateAddDelta(scores, party, delta) {
    if (scores && scores[party] !== undefined) {
        scores[party] += delta
    }
}

var ELECTORATE_SCOPES = { stratum: 1, district: 1, global: 1 }

class ElectorateModifier {
    /**
     * Positional (table-friendly):
     *   new ElectorateModifier(rowId, stackId, scope, target, party, delta [, activeIf])
     *   new ElectorateModifier(stackId, scope, target, party, delta [, activeIf])  // legacy: rowId = stackId
     * stackId: Q quality for stacks (favor_second_wave_housing_dispute += 1).
     * scope: 'stratum' | 'district' | 'global' — use '' for target when global.
     * Object form: { id, stackId?, scope, target, party, delta, activeIf? }
     */
    constructor(rowId, stackId, scope, target, party, delta, activeIf) {
        var fromObject = rowId && typeof rowId === 'object'
        if (fromObject) {
            var opts = rowId
            rowId = opts.id
            stackId = opts.stackId != null ? opts.stackId : opts.id
            scope = opts.scope
            target = opts.target
            party = opts.party
            delta = opts.delta
            activeIf = opts.activeIf
            this.gateWithActiveIf = activeIf != null
        } else if (ELECTORATE_SCOPES[stackId]) {
            // legacy: (stackId, scope, target, party, delta [, activeIf])
            activeIf = delta
            delta = party
            party = target
            target = scope
            scope = stackId
            stackId = rowId
            this.gateWithActiveIf = arguments.length >= 6 && activeIf != null
        } else {
            this.gateWithActiveIf = arguments.length >= 7 && activeIf != null
        }
        this.id = rowId
        this.stackId = stackId || rowId
        this.scope = scope
        this.target = target || ''
        this.party = party
        this.delta = delta || 0
        this.activeIf = activeIf || function() { return true }
    }

    /** Stack count from Q[stackId]; non-numeric or <= 0 → no effect. */
    stacksFromQ(q) {
        if (!q || q[this.stackId] == null) { return 0 }
        var n = Number(q[this.stackId])
        if (isNaN(n) || n <= 0) { return 0 }
        return n
    }

    isActive(q) {
        try {
            return !!this.activeIf(q)
        } catch (e) {
            return false
        }
    }

    apply(state, q) {
        var stacks = this.stacksFromQ(q)
        if (stacks <= 0) { return }
        if (this.gateWithActiveIf && !this.isActive(q)) { return }
        var shift = this.delta * stacks
        if (this.scope === 'stratum') {
            var dem = state.demographicsById[this.target]
            if (dem) { electorateAddDelta(dem.competitiveScores, this.party, shift) }
        } else if (this.scope === 'district') {
            var dist = state.districtsById[this.target]
            if (dist) { electorateAddDelta(dist.competitiveScores, this.party, shift) }
        } else if (this.scope === 'global') {
            electorateAddDelta(state.global.competitiveScores, this.party, shift)
        }
    }
}

