function electorateZeroScores() {
    return { D: 0, I: 0, C: 0, G: 0, H: 0 }
}

function electorateCopyScores(src) {
    var out = electorateZeroScores()
    for (var i = 0; i < ELECTORATE_PARTY_KEYS.length; i++) {
        var k = ELECTORATE_PARTY_KEYS[i]
        out[k] = (src && src[k]) || 0
