class ElectorateModifier {
    /**
     * Positional (table-friendly):
     *   new ElectorateModifier(rowId, stackId, scope, target, party, delta [, activeIf])
     *   new ElectorateModifier(stackId, scope, target, party, delta [, activeIf])  // legacy: rowId = stackId
     * stackId: Q quality for stacks (favor_second_wave_housing_dispute += 1).
     * scope: 'stratum' | 'district' | 'global' — use '' for target when global.
     * Object form: { id, stackId?, scope, target, party, delta, activeIf? }
