    constructor(rowId, stackId, scope, target, party, delta, activeIf) {
        var fromObject = rowId && typeof rowId === 'object'
        if (fromObject) {
            var opts = rowId
            rowId = opts.id
            stackId = opts.stackId != null ? opts.stackId : opts.id
            scope = opts.scope
            target = opts.target
            party = opts.party
            delta = opts.delta
            activeIf = opts.activeIf
            this.gateWithActiveIf = activeIf != null
        } else if (ELECTORATE_SCOPES[stackId]) {
            // legacy: (stackId, scope, target, party, delta [, activeIf])
            activeIf = delta
